const DB_NAME = 'SiteInspectorDb';
const DB_VERSION = 1;

let db = null;

function openDb() {
    return new Promise((resolve, reject) => {
        if (db) { resolve(db); return; }
        const request = indexedDB.open(DB_NAME, DB_VERSION);
        request.onupgradeneeded = (e) => {
            const database = e.target.result;
            if (!database.objectStoreNames.contains('sites')) {
                database.createObjectStore('sites', { keyPath: 'id' });
            }
            if (!database.objectStoreNames.contains('inspections')) {
                const store = database.createObjectStore('inspections', { keyPath: 'id' });
                store.createIndex('siteId', 'siteId', { unique: false });
                store.createIndex('syncStatus', 'syncStatus', { unique: false });
            }
            if (!database.objectStoreNames.contains('photos')) {
                const store = database.createObjectStore('photos', { keyPath: 'id' });
                store.createIndex('inspectionId', 'inspectionId', { unique: false });
            }
        };
        request.onsuccess = (e) => { db = e.target.result; resolve(db); };
        request.onerror = (e) => reject(e.target.error);
    });
}

function doTransaction(storeName, mode, operation) {
    return openDb().then(database => {
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, mode);
            const store = tx.objectStore(storeName);
            const result = operation(store);
            if (result && result.onsuccess !== undefined) {
                result.onsuccess = () => resolve(result.result);
                result.onerror = () => reject(result.error);
            } else {
                tx.oncomplete = () => resolve(result);
                tx.onerror = () => reject(tx.error);
            }
        });
    });
}

window.indexedDbInterop = {
    put: (storeName, data) => {
        const item = JSON.parse(data);
        return doTransaction(storeName, 'readwrite', store => store.put(item));
    },

    get: (storeName, id) => {
        return doTransaction(storeName, 'readonly', store => store.get(id))
            .then(result => result ? JSON.stringify(result) : null);
    },

    getAll: (storeName) => {
        return openDb().then(database => {
            return new Promise((resolve, reject) => {
                const tx = database.transaction(storeName, 'readonly');
                const store = tx.objectStore(storeName);
                const request = store.getAll();
                request.onsuccess = () => resolve(JSON.stringify(request.result));
                request.onerror = () => reject(request.error);
            });
        });
    },

    getAllByIndex: (storeName, indexName, value) => {
        return openDb().then(database => {
            return new Promise((resolve, reject) => {
                const tx = database.transaction(storeName, 'readonly');
                const store = tx.objectStore(storeName);
                const index = store.index(indexName);
                const request = index.getAll(value);
                request.onsuccess = () => resolve(JSON.stringify(request.result));
                request.onerror = () => reject(request.error);
            });
        });
    },

    delete: (storeName, id) => {
        return doTransaction(storeName, 'readwrite', store => store.delete(id));
    },

    clear: (storeName) => {
        return doTransaction(storeName, 'readwrite', store => store.clear());
    }
};

window.connectivityInterop = {
    isOnline: () => navigator.onLine,

    registerOnlineHandler: (dotNetHelper) => {
        window.addEventListener('online', () => {
            dotNetHelper.invokeMethodAsync('OnConnectivityChanged', true);
        });
        window.addEventListener('offline', () => {
            dotNetHelper.invokeMethodAsync('OnConnectivityChanged', false);
        });
    }
};

window.photoInterop = {
    readFileAsDataUrl: (inputId) => {
        return new Promise((resolve, reject) => {
            const input = document.getElementById(inputId);
            if (!input || !input.files || input.files.length === 0) {
                resolve(null);
                return;
            }
            const file = input.files[0];
            // Resize for mobile — cap at 1200px to save IndexedDB space
            const img = new Image();
            const reader = new FileReader();
            reader.onload = (e) => {
                img.onload = () => {
                    const MAX = 1200;
                    let w = img.width, h = img.height;
                    if (w > MAX || h > MAX) {
                        const ratio = Math.min(MAX / w, MAX / h);
                        w = Math.round(w * ratio);
                        h = Math.round(h * ratio);
                    }
                    const canvas = document.createElement('canvas');
                    canvas.width = w;
                    canvas.height = h;
                    canvas.getContext('2d').drawImage(img, 0, 0, w, h);
                    resolve(JSON.stringify({
                        dataUrl: canvas.toDataURL('image/jpeg', 0.8),
                        fileName: file.name
                    }));
                };
                img.src = e.target.result;
            };
            reader.onerror = () => reject(reader.error);
            reader.readAsDataURL(file);
        });
    },

    clearFileInput: (inputId) => {
        const input = document.getElementById(inputId);
        if (input) input.value = '';
    }
};

using System.Text.Json;
using System.Text.Json.Serialization;
using Microsoft.JSInterop;

namespace SiteInspector.Services;

public class IndexedDbService
{
    private readonly IJSRuntime _js;

    private static readonly JsonSerializerOptions JsonOptions = new()
    {
        PropertyNamingPolicy = JsonNamingPolicy.CamelCase,
        Converters = { new JsonStringEnumConverter() }
    };

    public IndexedDbService(IJSRuntime js) => _js = js;

    public async Task PutAsync<T>(string storeName, T item)
    {
        var json = JsonSerializer.Serialize(item, JsonOptions);
        await _js.InvokeVoidAsync("indexedDbInterop.put", storeName, json);
    }

    public async Task<T?> GetAsync<T>(string storeName, string id)
    {
        var json = await _js.InvokeAsync<string?>("indexedDbInterop.get", storeName, id);
        return json is null ? default : JsonSerializer.Deserialize<T>(json, JsonOptions);
    }

    public async Task<List<T>> GetAllAsync<T>(string storeName)
    {
        var json = await _js.InvokeAsync<string>("indexedDbInterop.getAll", storeName);
        return JsonSerializer.Deserialize<List<T>>(json, JsonOptions) ?? [];
    }

    public async Task<List<T>> GetAllByIndexAsync<T>(string storeName, string indexName, string value)
    {
        var json = await _js.InvokeAsync<string>("indexedDbInterop.getAllByIndex", storeName, indexName, value);
        return JsonSerializer.Deserialize<List<T>>(json, JsonOptions) ?? [];
    }

    public async Task DeleteAsync(string storeName, string id)
    {
        await _js.InvokeVoidAsync("indexedDbInterop.delete", storeName, id);
    }
}

using SiteInspector.Models;

namespace SiteInspector.Services;

public class InspectionStore
{
    private readonly IndexedDbService _db;

    public InspectionStore(IndexedDbService db) => _db = db;

    // Sites
    public Task<List<ConstructionSite>> GetSitesAsync() => _db.GetAllAsync<ConstructionSite>("sites");
    public Task<ConstructionSite?> GetSiteAsync(string id) => _db.GetAsync<ConstructionSite>("sites", id);
    public Task SaveSiteAsync(ConstructionSite site) => _db.PutAsync("sites", site);
    public Task DeleteSiteAsync(string id) => _db.DeleteAsync("sites", id);

    // Inspections
    public Task<List<Inspection>> GetInspectionsAsync() => _db.GetAllAsync<Inspection>("inspections");

    public Task<List<Inspection>> GetInspectionsForSiteAsync(string siteId) =>
        _db.GetAllByIndexAsync<Inspection>("inspections", "siteId", siteId);

    public Task<Inspection?> GetInspectionAsync(string id) => _db.GetAsync<Inspection>("inspections", id);

    public Task SaveInspectionAsync(Inspection inspection)
    {
        inspection.UpdatedAt = DateTime.UtcNow;
        return _db.PutAsync("inspections", inspection);
    }

    public Task DeleteInspectionAsync(string id) => _db.DeleteAsync("inspections", id);

    public async Task<List<Inspection>> GetPendingSyncAsync()
    {
        var all = await GetInspectionsAsync();
        return all.Where(i => i.SyncStatus == SyncStatus.Pending && i.Status == InspectionStatus.Completed).ToList();
    }

    // Photos
    public Task<List<InspectionPhoto>> GetPhotosForInspectionAsync(string inspectionId) =>
        _db.GetAllByIndexAsync<InspectionPhoto>("photos", "inspectionId", inspectionId);

    public Task SavePhotoAsync(InspectionPhoto photo) => _db.PutAsync("photos", photo);
    public Task DeletePhotoAsync(string id) => _db.DeleteAsync("photos", id);
}

using Microsoft.JSInterop;

namespace SiteInspector.Services;

public class ConnectivityService : IAsyncDisposable
{
    private readonly IJSRuntime _js;
    private DotNetObjectReference<ConnectivityService>? _dotNetRef;

    public bool IsOnline { get; private set; }
    public event Action<bool>? ConnectivityChanged;

    public ConnectivityService(IJSRuntime js) => _js = js;

    public async Task InitializeAsync()
    {
        _dotNetRef = DotNetObjectReference.Create(this);
        IsOnline = await _js.InvokeAsync<bool>("connectivityInterop.isOnline");
        await _js.InvokeVoidAsync("connectivityInterop.registerOnlineHandler", _dotNetRef);
    }

    [JSInvokable]
    public Task OnConnectivityChanged(bool isOnline)
    {
        IsOnline = isOnline;
        ConnectivityChanged?.Invoke(isOnline);
        return Task.CompletedTask;
    }

    public async ValueTask DisposeAsync()
    {
        _dotNetRef?.Dispose();
        await ValueTask.CompletedTask;
    }
}

using System.Net.Http.Json;
using SiteInspector.Models;

namespace SiteInspector.Services;

/// <summary>
/// Syncs completed inspections to the server when connectivity is available.
/// In this initial version the server endpoint is not yet deployed, so sync
/// attempts are logged but gracefully tolerate failures.
/// </summary>
public class SyncService : IDisposable
{
