    public SyncService(InspectionStore store, ConnectivityService connectivity, HttpClient http)
    {
        _store = store;
        _connectivity = connectivity;
        _http = http;
    }

    public void Start()
    {
        _connectivity.ConnectivityChanged += OnConnectivityChanged;
        _timer = new Timer(async _ => await TrySyncAsync(), null, TimeSpan.FromSeconds(5), TimeSpan.FromSeconds(30));
    }

    private async void OnConnectivityChanged(bool isOnline)
    {
        if (isOnline)
            await TrySyncAsync();
    }

    public async Task TrySyncAsync()
    {
        try
