using System.Net.Http.Json;
using SiteInspector.Models;

namespace SiteInspector.Services;

/// <summary>
/// Syncs completed inspections to the server when connectivity is available.
/// In this initial version the server endpoint is not yet deployed, so sync
/// attempts are logged but gracefully tolerate failures.
/// </summary>
public class SyncService : IDisposable
{
    private readonly InspectionStore _store;
    private readonly ConnectivityService _connectivity;
    private readonly HttpClient _http;
    private Timer? _timer;

    public int PendingCount { get; private set; }
    public event Action? SyncStateChanged;

    public SyncService(InspectionStore store, ConnectivityService connectivity, HttpClient http)
    {
        _store = store;
        _connectivity = connectivity;
        _http = http;
    }

    public void Start()
    {
        _connectivity.ConnectivityChanged += OnConnectivityChanged;
        _timer = new Timer(async _ => await TrySyncAsync(), null, TimeSpan.FromSeconds(5), TimeSpan.FromSeconds(30));
    }

    private async void OnConnectivityChanged(bool isOnline)
    {
        if (isOnline)
            await TrySyncAsync();
    }

    public async Task TrySyncAsync()
    {
        try
        {
            var pending = await _store.GetPendingSyncAsync();
            PendingCount = pending.Count;
            SyncStateChanged?.Invoke();

            if (!_connectivity.IsOnline || pending.Count == 0)
                return;

            foreach (var inspection in pending)
            {
                try
                {
                    // Attempt to POST to a server endpoint.
                    // The server API is not yet implemented — this will fail gracefully
                    // and the inspection stays queued for the next attempt.
                    var response = await _http.PostAsJsonAsync("api/inspections", inspection);
                    if (response.IsSuccessStatusCode)
                    {
                        inspection.SyncStatus = SyncStatus.Synced;
                        await _store.SaveInspectionAsync(inspection);
                    }
                }
                catch
                {
                    // Network error — will retry on next cycle
                }
            }

            pending = await _store.GetPendingSyncAsync();
            PendingCount = pending.Count;
            SyncStateChanged?.Invoke();
        }
        catch
        {
            // Swallow — offline resilience is the priority
        }
    }

    public void Dispose()
    {
        _connectivity.ConnectivityChanged -= OnConnectivityChanged;
        _timer?.Dispose();
    }
}

