arguments.file_text:
@page "/"
@using SiteInspector.Models
@using SiteInspector.Services
@inject InspectionStore Store
@inject NavigationManager Nav

<div class="page-header">
    <h1>🏗️ Sites</h1>
    <button class="btn btn-primary btn-add" @onclick="ShowAddForm">+ New Site</button>
</div>

@if (_showAddForm)
{
    <div class="card mb-3">
        <div class="card-body">
            <div class="mb-2">
                <input class="form-control form-control-lg" placeholder="Site name" @bind="_newName" @bind:event="oninput" />
            </div>
            <div class="mb-2">
                <input class="form-control" placeholder="Address" @bind="_newAddress" @bind:event="oninput" />
            </div>
            <div class="d-flex gap-2">
                <button class="btn btn-success flex-fill" @onclick="AddSite" disabled="@string.IsNullOrWhiteSpace(_newName)">Save</button>
                <button class="btn btn-outline-secondary flex-fill" @onclick="() => _showAddForm = false">Cancel</button>
            </div>
        </div>
    </div>
}

@if (_sites is null)
{
    <p class="text-muted">Loading…</p>
}
else if (_sites.Count == 0)
{
    <div class="empty-state">
        <div class="empty-icon">🏢</div>
        <p>No construction sites yet.<br/>Tap <strong>+ New Site</strong> to get started.</p>
    </div>
}
else
{
    <div class="site-list">
        @foreach (var site in _sites.OrderByDescending(s => s.CreatedAt))
        {
            <div class="site-card" @onclick="() => Nav.NavigateTo($&quot;site/{site.Id}&quot;)">
                <div class="site-name">@site.Name</div>
                <div class="site-address">@site.Address</div>
            </div>
        }
    </div>
}

@code {
    private List<ConstructionSite>? _sites;
    private bool _showAddForm;
    private string _newName = string.Empty;
    private string _newAddress = string.Empty;

    protected override async Task OnInitializedAsync()
    {
        _sites = await Store.GetSitesAsync();
    }

    private void ShowAddForm()
    {
        _showAddForm = true;
        _newName = string.Empty;
        _newAddress = string.Empty;
    }

    private async Task AddSite()
    {
        if (string.IsNullOrWhiteSpace(_newName)) return;
        var site = new ConstructionSite { Name = _newName.Trim(), Address = _newAddress.Trim() };
        await Store.SaveSiteAsync(site);
        _sites = await Store.GetSitesAsync();
        _showAddForm = false;
    }
}

.page-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 1rem;
}

.page-header h1 {
    font-size: 1.4rem;
    margin: 0;
}

.btn-add {
    font-size: 1rem;
    padding: 0.5rem 1rem;
    border-radius: 2rem;
}

.empty-state {
    text-align: center;
    padding: 3rem 1rem;
    color: #6c757d;
}

.empty-icon {
    font-size: 3rem;
    margin-bottom: 1rem;
}

.site-list {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
}

.site-card {
    background: white;
    border: 1px solid #dee2e6;
    border-radius: 0.75rem;
    padding: 1rem;
    cursor: pointer;
    transition: background 0.1s;
    -webkit-tap-highlight-color: transparent;
}

.site-card:active {
    background: #e9ecef;
}

.site-name {
    font-weight: 600;
    font-size: 1.1rem;
}

.site-address {
    color: #6c757d;
    font-size: 0.9rem;
}

@page "/site/{SiteId}"
@using SiteInspector.Models
@using SiteInspector.Services
@inject InspectionStore Store
@inject NavigationManager Nav

<div class="page-header">
    <button class="btn btn-link btn-back" @onclick='() => Nav.NavigateTo("/")'>← Back</button>
    <h1>@(_site?.Name ?? "Site")</h1>
</div>

@if (_site is not null)
{
    <p class="text-muted mb-3">@_site.Address</p>

    <button class="btn btn-primary btn-lg w-100 mb-3" @onclick="StartNewInspection">
        📋 New Inspection
    </button>
}

@if (_inspections is null)
{
    <p class="text-muted">Loading…</p>
}
else if (_inspections.Count == 0)
{
    <div class="empty-state">
        <div class="empty-icon">📋</div>
        <p>No inspections yet for this site.</p>
    </div>
}
else
{
    <h2 class="section-title">Inspection History</h2>
    <div class="inspection-list">
        @foreach (var insp in _inspections.OrderByDescending(i => i.InspectionDate))
        {
            var passCount = insp.Checklist.Count(c => c.Result == CheckResult.Pass);
            var failCount = insp.Checklist.Count(c => c.Result == CheckResult.Fail);
            var total = insp.Checklist.Count;

            <div class="inspection-card" @onclick="() => Nav.NavigateTo($&quot;inspection/{insp.Id}&quot;)">
                <div class="d-flex justify-content-between align-items-start">
                    <div>
                        <div class="insp-date">@insp.InspectionDate.ToLocalTime().ToString("MMM d, yyyy h:mm tt")</div>
                        @if (!string.IsNullOrEmpty(insp.InspectorName))
                        {
                            <div class="insp-inspector">@insp.InspectorName</div>
                        }
                    </div>
                    <div class="d-flex gap-2 align-items-center">
                        @if (insp.Status == InspectionStatus.InProgress)
                        {
                            <span class="badge bg-warning text-dark">In Progress</span>
                        }
                        else
                        {
                            <span class="badge bg-success">Completed</span>
                        }
                        @if (insp.SyncStatus == SyncStatus.Pending)
                        {
                            <span class="badge bg-secondary" title="Not yet synced">⏳</span>
                        }
                        else if (insp.SyncStatus == SyncStatus.Synced)
                        {
                            <span class="badge bg-info" title="Synced">☁️</span>
                        }
                    </div>
                </div>
                <div class="insp-stats">
                    <span class="text-success">✓ @passCount</span>
                    <span class="text-danger ms-2">✗ @failCount</span>
                    <span class="text-muted ms-2">/ @total items</span>
                    @if (insp.PhotoIds.Count > 0)
                    {
                        <span class="ms-2">📷 @insp.PhotoIds.Count</span>
                    }
                </div>
            </div>
        }
    </div>
}

@code {
    [Parameter] public string SiteId { get; set; } = string.Empty;

    private ConstructionSite? _site;
    private List<Inspection>? _inspections;

    protected override async Task OnInitializedAsync()
    {
        _site = await Store.GetSiteAsync(SiteId);
        _inspections = await Store.GetInspectionsForSiteAsync(SiteId);
    }

    private async Task StartNewInspection()
    {
        var inspection = new Inspection
        {
            SiteId = SiteId,
            SiteName = _site?.Name ?? "",
            Checklist = ChecklistTemplates.GetStandardChecklist()
        };
        await Store.SaveInspectionAsync(inspection);
        Nav.NavigateTo($"inspection/{inspection.Id}");
    }
}

