    font-size: 1rem;
    font-weight: 600;
    color: #6c757d;
    text-transform: uppercase;
    letter-spacing: 0.05em;
    margin-bottom: 0.75rem;
}

.empty-state {
    text-align: center;
    padding: 2rem 1rem;
    color: #6c757d;
}

.empty-icon {
    font-size: 2.5rem;
    margin-bottom: 0.5rem;
}

.inspection-list {
    display: flex;
    flex-direction: column;
