@page "/site/{SiteId}"
@using SiteInspector.Models
@using SiteInspector.Services
@inject InspectionStore Store
@inject NavigationManager Nav

<div class="page-header">
    <button class="btn btn-link btn-back" @onclick='() => Nav.NavigateTo("/")'>← Back</button>
    <h1>@(_site?.Name ?? "Site")</h1>
</div>

@if (_site is not null)
{
    <p class="text-muted mb-3">@_site.Address</p>

    <button class="btn btn-primary btn-lg w-100 mb-3" @onclick="StartNewInspection">
        📋 New Inspection
    </button>
}

@if (_inspections is null)
{
    <p class="text-muted">Loading…</p>
}
else if (_inspections.Count == 0)
{
    <div class="empty-state">
        <div class="empty-icon">📋</div>
        <p>No inspections yet for this site.</p>
    </div>
}
else
{
    <h2 class="section-title">Inspection History</h2>
    <div class="inspection-list">
        @foreach (var insp in _inspections.OrderByDescending(i => i.InspectionDate))
        {
            var passCount = insp.Checklist.Count(c => c.Result == CheckResult.Pass);
            var failCount = insp.Checklist.Count(c => c.Result == CheckResult.Fail);
            var total = insp.Checklist.Count;

            <div class="inspection-card" @onclick="() => Nav.NavigateTo($&quot;inspection/{insp.Id}&quot;)">
                <div class="d-flex justify-content-between align-items-start">
                    <div>
                        <div class="insp-date">@insp.InspectionDate.ToLocalTime().ToString("MMM d, yyyy h:mm tt")</div>
                        @if (!string.IsNullOrEmpty(insp.InspectorName))
                        {
                            <div class="insp-inspector">@insp.InspectorName</div>
                        }
                    </div>
                    <div class="d-flex gap-2 align-items-center">
                        @if (insp.Status == InspectionStatus.InProgress)
                        {
                            <span class="badge bg-warning text-dark">In Progress</span>
                        }
                        else
                        {
                            <span class="badge bg-success">Completed</span>
                        }
                        @if (insp.SyncStatus == SyncStatus.Pending)
                        {
                            <span class="badge bg-secondary" title="Not yet synced">⏳</span>
                        }
                        else if (insp.SyncStatus == SyncStatus.Synced)
                        {
                            <span class="badge bg-info" title="Synced">☁️</span>
                        }
                    </div>
                </div>
                <div class="insp-stats">
                    <span class="text-success">✓ @passCount</span>
                    <span class="text-danger ms-2">✗ @failCount</span>
                    <span class="text-muted ms-2">/ @total items</span>
                    @if (insp.PhotoIds.Count > 0)
                    {
                        <span class="ms-2">📷 @insp.PhotoIds.Count</span>
                    }
                </div>
            </div>
        }
    </div>
}

