    font-size: 1.2rem;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    -webkit-tap-highlight-color: transparent;
    transition: all 0.1s;
}

.btn-check-result:active {
    transform: scale(0.95);
}

.btn-check-result.active-pass {
    background: #198754;
    color: white;
    border-color: #198754;
}

.btn-check-result.active-fail {
    background: #dc3545;
    color: white;
    border-color: #dc3545;
}

.btn-check-result.active-na {
    background: #6c757d;
    color: white;
    border-color: #6c757d;
}

.item-notes {
    margin-top: 0.35rem;
    font-size: 0.85rem;
}

.photo-grid {
    display: grid;
    grid-template-columns: 1fr;
    gap: 0.75rem;
}

.photo-card {
    border: 1px solid #dee2e6;
    border-radius: 0.75rem;
    overflow: hidden;
}

.photo-img {
    width: 100%;
