@page "/inspection/{InspectionId}"
@using SiteInspector.Models
@using SiteInspector.Services
@inject InspectionStore Store
@inject NavigationManager Nav
@inject IJSRuntime JS

<div class="page-header">
    <button class="btn btn-link btn-back" @onclick="GoBack">← Back</button>
    <h1>Inspection</h1>
    @if (_inspection?.Status == InspectionStatus.InProgress)
    {
        <button class="btn btn-success btn-sm ms-auto" @onclick="CompleteInspection">✓ Complete</button>
    }
    else
    {
        <span class="badge bg-success ms-auto">Completed</span>
    }
</div>

@if (_inspection is null)
{
    <p class="text-muted">Loading…</p>
}
else
{
    <!-- Tab Bar -->
    <div class="tab-bar">
        <button class="tab @(_activeTab == Tab.Checklist ? "active" : "")" @onclick="() => _activeTab = Tab.Checklist">
            📋 Checklist
        </button>
        <button class="tab @(_activeTab == Tab.Photos ? "active" : "")" @onclick="() => _activeTab = Tab.Photos">
            📷 Photos <span class="tab-count">@_photos.Count</span>
        </button>
        <button class="tab @(_activeTab == Tab.Notes ? "active" : "")" @onclick="() => _activeTab = Tab.Notes">
            📝 Notes
        </button>
    </div>

    @if (_activeTab == Tab.Checklist)
    {
        <div class="mb-3">
            <input class="form-control" placeholder="Inspector name" @bind="_inspection.InspectorName"
                   @bind:after="SaveAsync" />
        </div>

        <!-- Progress bar -->
        @{
            var inspected = _inspection.Checklist.Count(c => c.Result != CheckResult.NotInspected);
            var total = _inspection.Checklist.Count;
            var pct = total > 0 ? (int)(100.0 * inspected / total) : 0;
        }
        <div class="progress mb-3" style="height: 0.5rem;">
            <div class="progress-bar bg-info" style="width: @(pct)%"></div>
        </div>
        <div class="text-muted small mb-2">@inspected / @total items inspected</div>

        @foreach (var category in _inspection.Checklist.Select(c => c.Category).Distinct())
        {
            <div class="category-header" @onclick="() => ToggleCategory(category)">
                <span>@(_collapsedCategories.Contains(category) ? "▶" : "▼") @category</span>
                @{
                    var catItems = _inspection.Checklist.Where(c => c.Category == category).ToList();
                    var catFails = catItems.Count(c => c.Result == CheckResult.Fail);
                }
                @if (catFails > 0)
                {
                    <span class="badge bg-danger">@catFails fail</span>
                }
            </div>

            @if (!_collapsedCategories.Contains(category))
            {
                @foreach (var item in _inspection.Checklist.Where(c => c.Category == category))
                {
                    <div class="checklist-item @(item.Result == CheckResult.Fail ? "item-fail" : item.Result == CheckResult.Pass ? "item-pass" : "")">
                        <div class="item-description">@item.Description</div>
                        <div class="item-buttons">
                            <button class="btn-check-result @(item.Result == CheckResult.Pass ? "active-pass" : "")"
                                    @onclick="() => SetResult(item, CheckResult.Pass)" title="Pass">✓</button>
                            <button class="btn-check-result @(item.Result == CheckResult.Fail ? "active-fail" : "")"
                                    @onclick="() => SetResult(item, CheckResult.Fail)" title="Fail">✗</button>
                            <button class="btn-check-result @(item.Result == CheckResult.NotApplicable ? "active-na" : "")"
                                    @onclick="() => SetResult(item, CheckResult.NotApplicable)" title="N/A">—</button>
                        </div>
                        @if (item.Result == CheckResult.Fail || !string.IsNullOrEmpty(item.Notes))
                        {
                            <input class="form-control form-control-sm item-notes" placeholder="Add note…"
                                   @bind="item.Notes" @bind:after="SaveAsync" />
                        }
                    </div>
                }
            }
        }
    }
    else if (_activeTab == Tab.Photos)
    {
        <div class="mb-3">
            <label class="btn btn-outline-primary w-100 btn-lg">
                📷 Take Photo or Choose File
                <input type="file" accept="image/*" capture="environment" id="photoInput"
                       @onchange="OnPhotoSelected" style="display:none" />
            </label>
        </div>

        @if (_photos.Count == 0)
        {
            <div class="empty-state">
                <p>No photos yet. Tap above to add one.</p>
            </div>
        }
        else
        {
            <div class="photo-grid">
                @foreach (var photo in _photos.OrderByDescending(p => p.TakenAt))
                {
                    <div class="photo-card">
                        <img src="@photo.DataUrl" alt="@photo.Caption" class="photo-img" />
                        <div class="photo-info">
                            <input class="form-control form-control-sm" placeholder="Caption…"
                                   @bind="photo.Caption" @bind:after="() => Store.SavePhotoAsync(photo)" />
                            <button class="btn btn-sm btn-outline-danger mt-1" @onclick="() => DeletePhoto(photo)">Remove</button>
                        </div>
                    </div>
                }
            </div>
        }
    }
    else if (_activeTab == Tab.Notes)
    {
        <div class="mb-2">
            <label class="form-label fw-bold">General Notes</label>
            <textarea class="form-control" rows="8" placeholder="Site conditions, weather, observations…"
                      @bind="_inspection.GeneralNotes" @bind:after="SaveAsync"></textarea>
        </div>
        <div class="text-muted small">
            Inspection started: @_inspection.CreatedAt.ToLocalTime().ToString("MMM d, yyyy h:mm tt")
        </div>
    }
}

@code {
    [Parameter] public string InspectionId { get; set; } = string.Empty;

    private Inspection? _inspection;
    private List<InspectionPhoto> _photos = new();
    private Tab _activeTab = Tab.Checklist;
    private HashSet<string> _collapsedCategories = new();

    private enum Tab { Checklist, Photos, Notes }

    protected override async Task OnInitializedAsync()
    {
        _inspection = await Store.GetInspectionAsync(InspectionId);
        if (_inspection is not null)
        {
            _photos = await Store.GetPhotosForInspectionAsync(InspectionId);
        }
    }

    private async Task SetResult(ChecklistItem item, CheckResult result)
    {
        item.Result = item.Result == result ? CheckResult.NotInspected : result;
        await SaveAsync();
    }

    private async Task SaveAsync()
    {
        if (_inspection is not null)
            await Store.SaveInspectionAsync(_inspection);
    }

    private void ToggleCategory(string category)
    {
        if (!_collapsedCategories.Remove(category))
            _collapsedCategories.Add(category);
    }

    private async Task OnPhotoSelected()
    {
        if (_inspection is null) return;

        var json = await JS.InvokeAsync<string?>("photoInterop.readFileAsDataUrl", "photoInput");
        if (json is null) return;

        var result = System.Text.Json.JsonSerializer.Deserialize<PhotoResult>(json);
        if (result is null) return;

        var photo = new InspectionPhoto
        {
            InspectionId = InspectionId,
            FileName = result.FileName ?? "photo.jpg",
            DataUrl = result.DataUrl ?? ""
        };
        await Store.SavePhotoAsync(photo);
        _inspection.PhotoIds.Add(photo.Id);
        await SaveAsync();
        _photos = await Store.GetPhotosForInspectionAsync(InspectionId);
        await JS.InvokeVoidAsync("photoInterop.clearFileInput", "photoInput");
    }

    private async Task DeletePhoto(InspectionPhoto photo)
    {
        await Store.DeletePhotoAsync(photo.Id);
        if (_inspection is not null)
        {
            _inspection.PhotoIds.Remove(photo.Id);
            await SaveAsync();
        }
        _photos = await Store.GetPhotosForInspectionAsync(InspectionId);
    }

    private async Task CompleteInspection()
    {
        if (_inspection is null) return;
        _inspection.Status = InspectionStatus.Completed;
        await SaveAsync();
    }

    private void GoBack()
    {
        if (_inspection is not null)
            Nav.NavigateTo($"site/{_inspection.SiteId}");
        else
            Nav.NavigateTo("/");
    }

    private record PhotoResult(string? DataUrl, string? FileName);
}

